<?php declare(strict_types=1);require_once dirname(__DIR__).'/includes/cms.php';$pdo=obtenerConexion();$buscar=trim((string)($_GET['q']??''));$estado=(string)($_GET['estado']??'');$sql='SELECT p.*,c.nombre categoria FROM productos p LEFT JOIN categorias_producto c ON c.id=p.categoria_id WHERE p.eliminado_at IS NULL';$params=[];if($buscar!==''){$sql.=' AND (p.nombre LIKE :q OR p.sku LIKE :q)';$params['q']='%'.$buscar.'%';}if($estado==='activo')$sql.=' AND p.activo=1';elseif($estado==='inactivo')$sql.=' AND p.activo=0';elseif($estado==='agotado')$sql.=' AND p.stock<=p.stock_reservado';elseif($estado==='bajo')$sql.=' AND p.stock<=p.stock_minimo';$sql.=' ORDER BY p.updated_at DESC';$q=$pdo->prepare($sql);$q->execute($params);$filas=$q->fetchAll();cmsCabecera('Productos','productos/index.php','Administra catálogo, promociones e inventario con los componentes de StarAdmin.');?><div class="card card-rounded"><div class="card-body"><div class="d-flex flex-column flex-lg-row justify-content-between align-items-start gap-3 mb-4"><form class="d-flex gap-2 flex-wrap"><input class="form-control" name="q" value="<?=atenea_e($buscar)?>" placeholder="Buscar nombre o SKU"><select class="form-select" name="estado"><option value="">Todos</option><?php foreach(['activo'=>'Activos','inactivo'=>'Inactivos','agotado'=>'Agotados','bajo'=>'Bajo inventario']as$v=>$t):?><option value="<?=$v?>" <?=$estado===$v?'selected':''?>><?=$t?></option><?php endforeach;?></select><button class="btn btn-outline-primary">Filtrar</button></form><a class="btn btn-primary text-white" href="editar.php"><i class="mdi mdi-plus"></i> Nuevo producto</a></div><div class="table-responsive"><table class="table table-hover"><thead><tr><th>Producto</th><th>Categoría</th><th>Precio</th><th>Stock</th><th>Estado</th><th>Acciones</th></tr></thead><tbody><?php foreach($filas as$f):?><tr><td><div class="d-flex align-items-center"><img class="img-sm rounded me-2" src="<?=rutaImagenContenido($f['imagen_principal'],'src/website/assets/img/course-1.jpg')?>" alt=""><div><strong><?=atenea_e($f['nombre'])?></strong><small class="d-block text-muted"><?=atenea_e((string)$f['sku'])?></small></div></div></td><td><?=atenea_e((string)$f['categoria'])?></td><td>$<?=number_format((float)$f['precio'],2)?></td><td><span class="<?=$f['stock']<=$f['stock_minimo']?'text-danger fw-bold':''?>"><?=$f['stock']?> (reservado <?=$f['stock_reservado']?>)</span></td><td><span class="badge badge-opacity-<?=$f['activo']?'success':'secondary'?>"><?=$f['activo']?'Activo':'Inactivo'?></span></td><td><a class="btn btn-sm btn-outline-primary" href="editar.php?id=<?=$f['id']?>">Editar</a> <a class="btn btn-sm btn-outline-info" target="_blank" href="<?=atenea_url('src/website/product-details.php?id='.$f['id'])?>">Vista previa</a><form class="d-inline" method="post" action="accion.php"><input type="hidden" name="csrf_token" value="<?=atenea_e(obtenerTokenCsrf())?>"><input type="hidden" name="id" value="<?=$f['id']?>"><button class="btn btn-sm btn-outline-warning" name="accion" value="toggle"><?=$f['activo']?'Desactivar':'Activar'?></button> <button class="btn btn-sm btn-outline-danger" name="accion" value="eliminar" onclick="return confirm('¿Eliminar este producto?')">Eliminar</button></form></td></tr><?php endforeach;?><?php if(!$filas):?><tr><td colspan="6" class="text-center py-5 text-muted">No hay productos que coincidan.</td></tr><?php endif;?></tbody></table></div></div></div><?php cmsPie();?>
